# ════════════════════════════════════════════
# HELPERS
# ════════════════════════════════════════════
def time_ago(pub_dt_utc_naive):
    """pub_dt_utc_naive: naive datetime assumed UTC (as stored in PubDT)."""
    pub_aware = pub_dt_utc_naive.replace(tzinfo=timezone.utc) if pub_dt_utc_naive.tzinfo is None else pub_dt_utc_naive
    diff = now_local() - pub_aware
    m = int(diff.total_seconds() / 60)
    h = m // 60
    if m < 1:  return "Just now"
    if m < 60: return f"{m}m ago"
    if h < 24: return f"{h}h ago"
    return f"{diff.days}d ago"

def clean_html(text):
    text = re.sub(r'<[^>]+>', ' ', text or '')
    return re.sub(r'\s+', ' ', text).strip()

def detect_local(airlines_str):
    for a in LOCAL_AIRLINES:
        if a.lower() in airlines_str.lower():
            return a
    return None

def uid(title, link):
    return hashlib.md5(f"{title[:60]}{link}".encode()).hexdigest()

def is_relevant(full_lower):
    """True if article is relevant to our scope."""
    has_airline  = any(a.lower() in full_lower for a in AIRLINES_LIST)
    has_ksa      = any(k.lower() in full_lower for k in KSA_KW)
    has_me       = any(k.lower() in full_lower for k in ME_KW)
    has_aviation = any(k.lower() in full_lower for k in AVIATION_KW)
    # Include if: (any airline OR KSA OR ME) AND has aviation keyword
    return (has_airline or has_ksa or has_me) and has_aviation

# ════════════════════════════════════════════
# FETCH
# ════════════════════════════════════════════
UA = ("Mozilla/5.0 (Windows NT 10.0; Win64; x64) "
      "AppleWebKit/537.36 (KHTML, like Gecko) "
      "Chrome/120.0.0.0 Safari/537.36")

@st.cache_data(ttl=1800, show_spinner=False)   # cache 30 min
def fetch_news(days_back: int):
    articles = []
    seen     = set()
    log      = []
    # cutoff is computed in UTC, since feedparser's published_parsed is UTC
    cutoff = datetime.now(timezone.utc) - timedelta(days=days_back)

    for source_name, url in RSS_FEEDS:
        try:
            feed = feedparser.parse(url, request_headers={"User-Agent": UA})
            status = feed.get("status", 0)
            n      = len(feed.entries)

            if n == 0:
                log.append(f"⚠️  {source_name}: 0 entries (status={status})")
                continue

            log.append(f"✅ {source_name}: {n} entries (status={status})")

            for e in feed.entries:
                title   = clean_html(e.get("title",""))
                summary = clean_html(e.get("summary", e.get("description","")))
                link    = e.get("link","#")

                if not title or len(title) < 8:
                    continue

                entry_id = uid(title, link)
                if entry_id in seen:
                    continue
                seen.add(entry_id)

                # Parse published date — feedparser's *_parsed is UTC (struct_time)
                pub_dt = datetime.now(timezone.utc)
                for attr in ("published_parsed","updated_parsed","created_parsed"):
                    val = getattr(e, attr, None)
                    if val:
                        try:
                            pub_dt = datetime(*val[:6], tzinfo=timezone.utc)
                            break
                        except: pass

                # Skip articles older than days_back
                if pub_dt < cutoff:
                    continue

                full = f"{title} {summary}".lower()

                if not is_relevant(full):
                    continue

                airlines = [a for a in AIRLINES_LIST if a.lower() in full]
                is_ksa   = any(k.lower() in full for k in KSA_KW)
                is_me    = any(k.lower() in full for k in ME_KW)
                cat      = ("Operations / Infrastructure"
                            if any(w in full for w in OPS_WORDS)
                            else "Commercial / Fleet")
                al_str    = ", ".join(airlines) if airlines else "General Aviation"
                local     = any(la.lower() in al_str.lower() for la in LOCAL_AIRLINES)
                is_swiss  = "swissport" in full  # full-text match, not just airline-name match
                region   = ("Saudi Arabia 🇸🇦" if is_ksa
                            else ("Middle East 🌍" if is_me
                            else "Global / Regional"))

                articles.append({
                    "Title":   title,
                    "Summary": summary[:500],
                    "Link":    link,
                    "PubDT":   pub_dt,
                    "Airlines":al_str,
                    "Region":  region,
                    "Type":    cat,
                    "IsLocal": local,
                    "IsSwissport": is_swiss,   # ← New
                    "Source":  source_name,
                })

        except Exception as ex:
            log.append(f"💥 {source_name}: {type(ex).__name__}: {str(ex)[:60]}")
            continue

    log_str = "\n".join(log)
    if not articles:
        return pd.DataFrame(), log_str

    df = pd.DataFrame(articles)
    df["_tk"] = df["Title"].str.lower().str[:70].str.strip()
    df = df.drop_duplicates(subset="_tk").drop(columns="_tk")
    df = df.sort_values("PubDT", ascending=False).reset_index(drop=True)
    return df, log_str

